        StateStore::new(&inactive_effect, effect_aggregate_state([i64::MAX, 1])).unwrap();
    run_tick(&inactive_effect, &mut state, &params, 23, 0).unwrap();
    assert_eq!(state.snapshot().int("world", "Person", "y", 0).unwrap(), 0);

