    fn emit_resolve_kernel(&self, out: &mut String) -> Result<(), CudaError> {
        out.push_str("\nextern \"C\" __global__ void sembla_validate_claims(const unsigned char* state, const unsigned long long* column_offsets, const unsigned long long* row_counts, const unsigned char* inputs, const unsigned long long* input_offsets, const unsigned long long* input_counts, const unsigned char* params, const unsigned char* aggs, const unsigned long long* agg_offsets, const unsigned long long* candidate_offsets, const unsigned char* enabled, unsigned long long* status) {\n  if (blockIdx.x != 0 || threadIdx.x != 0 || status[0] != 0ULL) return;\n  unsigned char local_error = 0; unsigned char* error = &local_error;\n");
        for validated in self.model.transitions() {
            let transition = &self.model.model().boxes[validated.box_index].transitions
                [validated.transition_index];
            if transition.contests.is_empty() {
                continue;
            }
            let table_index = self.table_index(validated.box_index, &transition.table)?;
            let table_global = self.global_table(validated.box_index, table_index);
            let rows = Rows::State {
                box_index: validated.box_index,
                table_index,
            };
            writeln!(out, "  for (unsigned long long row = 0; row < row_counts[{table_global}]; ++row) {{ unsigned long long candidate = candidate_offsets[{}] + row;", validated.rule_id).unwrap();
            for claim in &transition.contests {
                let resource_ty = self.infer(&claim.resource, rows, None)?;
                let resource = self
                    .render(&claim.resource, rows, Some(&resource_ty), "state", "row")?
                    .0;
                writeln!(out, "    local_error = 0; (void)({resource});").unwrap();
                if let ClaimOrdering::Key { expr } = &claim.ordering {
                    let key = self.render(expr, rows, None, "state", "row")?.0;
                    writeln!(out, "    (void)({key});").unwrap();
