    fn claim_key(
        &self,
        claim: &sembla_ir::ResourceClaim,
        rows: Rows,
        _rule: u32,
        row: &str,
        candidate: &str,
    ) -> Result<(String, Ty), CudaError> {
        match &claim.ordering {
            ClaimOrdering::RaceTime => Ok((format!("times[{candidate}]"), Ty::Real)),
            ClaimOrdering::Key { expr } => self.render(expr, rows, None, "state", row),
        }
    }

