                (InputScalar::Real(lhs), InputScalar::Int(rhs)) => lhs == rhs as f64,
                (InputScalar::Int(lhs), InputScalar::Real(rhs)) => lhs as f64 == rhs,
                (InputScalar::Int(lhs), InputScalar::Int(rhs)) => lhs == rhs,
