diff --git a/crates/sembla-runtime/src/eval.rs b/crates/sembla-runtime/src/eval.rs
index db2ff8c..7005386 100644
--- a/crates/sembla-runtime/src/eval.rs
+++ b/crates/sembla-runtime/src/eval.rs
@@ -3,8 +3,9 @@
 //! Expressions are evaluated in syntax-tree order without reassociation. Real
 //! arithmetic therefore uses ordinary IEEE-754 `f64` semantics: in particular,
 //! division by zero produces infinity or NaN rather than a runtime error.
-//! Aggregate sums make one sequential target-table pass in ascending row order;
-//! that order is the canonical Level A CPU reduction order (`DESIGN.md` §5.2).
+//! Aggregate sums split target rows into two contiguous halves, scan each half
+//! in ascending row order, then merge half 0 before half 1. That fixed schedule
+//! is the canonical shared CPU/CUDA Level A reduction order (`DESIGN.md` §5.2).

 use std::error::Error;
 use std::fmt;
@@ -958,33 +959,66 @@ fn eval_input_aggregate(
             Ok(InternalColumn::Int(vec![count; result_rows]))
         }
         AggOp::Sum { value } => {
-            let mut int_sum = 0_i64;
-            let mut real_sum = 0.0;
-            let mut real = matches!(result_type, RuntimeType::Real);
-            for (row, keep) in selected.into_iter().enumerate() {
-                if !keep {
-                    continue;
-                }
-                match eval_input_scalar(value, input, row, params)? {
-                    InputScalar::Int(value) if !real => {
-                        int_sum = int_sum.checked_add(value).ok_or_else(|| {
-                            EvalError::new(format!("input aggregate integer overflow at row {row}"))
-                        })?;
+            // Level-A schedule shared with CUDA: ascending rows in two fixed
+            // contiguous halves, then partial 0 followed by partial 1.
+            let midpoint = input.row_count / 2;
+            match result_type {
+                RuntimeType::Real => {
+                    let mut partials = [0.0_f64; 2];
+                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
+                        .into_iter()
+                        .enumerate()
+                    {
+                        for row in range {
+                            if !selected[row] {
+                                continue;
+                            }
+                            match eval_input_scalar(value, input, row, params)? {
+                                InputScalar::Int(value) => partials[partial] += value as f64,
+                                InputScalar::Real(value) => partials[partial] += value,
+                                _ => {
+                                    return Err(EvalError::new(
+                                        "input aggregate Sum value is not numeric",
+                                    ))
+                                }
+                            }
+                        }
                     }
-                    InputScalar::Int(value) => real_sum += value as f64,
-                    InputScalar::Real(value) => {
-                        if !real {
-                            real_sum = int_sum as f64;
-                            real = true;
+                    Ok(InternalColumn::Real(vec![
+                        partials[0] + partials[1];
+                        result_rows
+                    ]))
+                }
+                RuntimeType::Int => {
+                    let mut partials = [0_i64; 2];
+                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
+                        .into_iter()
+                        .enumerate()
+                    {
+                        for row in range {
+                            if !selected[row] {
+                                continue;
+                            }
+                            let InputScalar::Int(value) =
+                                eval_input_scalar(value, input, row, params)?
+                            else {
